class FoodRatings {
    Map<String, Integer> foodMap;
    Map<String, Integer> cuisineMap;
    Map<String, Integer> cuisineFoodMap;

    public FoodRatings(String[] foods, String[] cuisines, int[] ratings) {
        foodMap = new HashMap<>();
        cuisineMap = new HashMap<>();
        cuisineFoodMap = new HashMap<>();
        for (int i = 0; i < foods.length; i++) {
            foodMap.put(foods[i], ratings[i]);
            cuisineMap.put(cuisines[i], ratings[i]);
            cuisineFoodMap.put(cuisines[i] + foods[i], ratings[i]);
        }
    }

    public void changeRating(String food, int newRating) {
        String cuisine = cuisineMap.get(food);
        int rating = foodMap.get(food);
        foodMap.put(food, newRating);
        cuisineMap.put(cuisine + food, newRating);
        cuisineFoodMap.put(cuisine + food, newRating);
    }

    public String highestRated(String cuisine) {
        String cuisine = cuisineMap.get(cuisine);
        String food = cuisineFoodMap.get(cuisine);
        int rating = foodMap.get(food);
        if (cuisineFoodMap.containsKey(cuisine + food)) {
            return cuisineFoodMap.get(cuisine + food);
        } else {
            String food = cuisineMap.get(cuisine);
            int rating = foodMap.get(food);
            cuisineFoodMap.put(cuisine + food, newRating);
            return cuisineFoodMap.get(cuisine + food);
        }
    }
}
